const config = $('HTTP Request').first().json;
const webhook = $('Recibir Mensaje').first().json.body;

const jidOriginal = webhook.jidOriginal || webhook.numeroOrigen;
const numeroDescifrado = webhook.numeroDescifrado || false;

const ZONA_HORARIA = 'America/Hermosillo';
const now = new Date();
const horaLocal = new Date(now.toLocaleString('en-US', { timeZone: ZONA_HORARIA }));
const hour = horaLocal.getHours();
const day = horaLocal.getDay();

const horaInicio = config.horario_inicio 
  ? parseInt(config.horario_inicio.split(':')[0]) 
  : (config.hora_inicio || 9);

const horaFin = config.horario_fin 
  ? parseInt(config.horario_fin.split(':')[0]) 
  : (config.hora_fin || 18);

let diasLaborales = [1, 2, 3, 4, 5];
if (config.dias_laborales) {
  try {
    diasLaborales = typeof config.dias_laborales === 'string' 
      ? JSON.parse(config.dias_laborales) 
      : config.dias_laborales;
  } catch (e) {
    console.log('⚠️ Error parseando dias_laborales:', e.message);
  }
}

const enDiaLaboral = diasLaborales.includes(day);
const enHorario = hour >= horaInicio && hour < horaFin;
const abierto = enDiaLaboral && enHorario;

const mensaje = webhook.mensaje || '';
const mensajeLimpio = mensaje.toLowerCase().trim();

let nombreSesion = config.sessionKey || 
                   webhook.sessionKey || 
                   `${webhook.empresaId}_empresa_${webhook.empresaId}`;

if (nombreSesion && nombreSesion.startsWith(`${webhook.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${webhook.empresaId}_`.length);
}

console.log('═══════════════════════════════════════════════════════════════');
console.log('🎯 MENSAJE RECIBIDO:', mensajeLimpio);
console.log('📞 Usuario:', webhook.numeroOrigen);
console.log('═══════════════════════════════════════════════════════════════');

const patronCancelarEspecifico = /\b(?:cancelar|cancela)\s+(?:pedido|orden)\s*#?(\d+)\b/i;
const matchCancelarEspecifico = mensajeLimpio.match(patronCancelarEspecifico);

if (matchCancelarEspecifico) {
  const pedidoId = matchCancelarEspecifico[1];
  console.log(`🎯 DETECTADO: Cancelar pedido específico #${pedidoId}`);
  return {
    json: {
      ...config,
      numeroOrigen: webhook.numeroOrigen,
      empresaId: webhook.empresaId,
      nombreSesion,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      mensaje_usuario: mensajeLimpio,
      pedidoId: parseInt(pedidoId),
      tipo: 'cancelar_pedido',
      mensaje: `🔄 *Procesando cancelación del pedido #${pedidoId}...*`,
      abierto
    }
  };
}

const patronCancelarGeneral = /^(?:cancelar|cancela)$/i;
const esCancelarGeneral = patronCancelarGeneral.test(mensajeLimpio);

if (!esCancelarGeneral) {
  const patronVerPedidos = /\b(mis?\s+pedidos?|ver\s+mis?\s+pedidos?|pedidos?|historial|mis?\s+compras?|ver\s+compras?|consultar\s+pedidos?|revisar\s+pedidos?|puedo\s+ver\s+mis?\s+pedidos?|quiero\s+ver\s+mis?\s+pedidos?)\b/i;
  if (patronVerPedidos.test(mensajeLimpio)) {
    console.log('✅ DETECTADO: Ver pedidos');
    return {
      json: {
        ...config,
        numeroOrigen: webhook.numeroOrigen,
        empresaId: webhook.empresaId,
        nombreSesion,
        pushName: webhook.pushName,
        jidOriginal,
        numeroDescifrado,
        mensaje_usuario: mensajeLimpio,
        tipo: 'ver_pedidos',
        mensaje: '📋 *Consultando tus pedidos...*',
        abierto
      }
    };
  }
}

try {
  const sesionData = await this.helpers.httpRequest({
    method: 'GET',
    url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
    json: true
  });

  if (sesionData && sesionData.success && sesionData.data) {
    const estadoActual = sesionData.data.estado;
    console.log('📋 Sesión encontrada - Estado:', estadoActual);

    if (estadoActual === 'seleccionando_categoria') {
      const datosSesion = typeof sesionData.data.datos_pedido === 'string'
        ? JSON.parse(sesionData.data.datos_pedido)
        : sesionData.data.datos_pedido;
      const categorias = datosSesion?.categorias || [];

      if (mensajeLimpio === 'cancelar') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: '✅ Operación cancelada.\n\n📋 Escribe *productos* para ver el catálogo.',
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }

      const opcion = parseInt(mensajeLimpio);
      if (!isNaN(opcion) && opcion >= 0 && opcion <= categorias.length) {
        console.log(`🏷️ Seleccionar categoría opción ${opcion}`);
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            tipo: 'seleccionar_categoria',
            categoriaOpcion: opcion,
            categorias,
            abierto
          }
        };
      }

      let msgInvalido = `❌ Opción no válida. Escribe un número del *0* al *${categorias.length}*:\n\n`;
      categorias.forEach((cat, i) => { msgInvalido += `*${i + 1}.* ${cat.nombre}\n`; });
      msgInvalido += `*0.* Ver todos los productos\n\n❌ O escribe *cancelar* para salir.`;
      return {
        json: {
          ...config,
          numeroOrigen: webhook.numeroOrigen,
          empresaId: webhook.empresaId,
          nombreSesion,
          pushName: webhook.pushName,
          jidOriginal,
          numeroDescifrado,
          mensaje_usuario: mensajeLimpio,
          mensaje: msgInvalido,
          tipo: 'respuesta_directa',
          abierto
        }
      };
    }

    if (estadoActual === 'confirmar_cancelacion') {
      if (mensajeLimpio === 'si' || mensajeLimpio === 'sí') {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: "❌ *Pedido cancelado exitosamente*\n\n✅ Si cambias de opinión, escribe *productos* para ver el catálogo.",
            tipo: 'respuesta_directa',
            abierto
          }
        };
      } else if (mensajeLimpio === 'no') {
        await this.helpers.httpRequest({
          method: 'PUT',
          url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
          headers: { 'Content-Type': 'application/json' },
          body: { estado: 'pendiente' },
          json: true
        });
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: "✅ *Pedido conservado*\n\n📝 Por favor, escribe tu *nombre completo* para confirmar el pedido.\n\n❌ O escribe *cancelar* si cambias de opinión.",
            tipo: 'respuesta_directa',
            abierto
          }
        };
      } else {
        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            mensaje_usuario: mensajeLimpio,
            mensaje: "⚠️ *Respuesta no válida*\n\n✅ Escribe *sí* para cancelar el pedido\n❌ Escribe *no* para continuar",
            tipo: 'respuesta_directa',
            abierto
          }
        };
      }
    }

    if (estadoActual === 'esperando_nombre') {
      const esComando =
        mensajeLimpio === 'cancelar' ||
        /^\d+$/.test(mensajeLimpio) ||
        /\b(productos?|cat[aá]logo|men[uú]|que tienen|que venden|ver productos)\b/i.test(mensajeLimpio) ||
        /\b(mis?\s+pedidos?|ver\s+mis?\s+pedidos?|pedidos?|historial|mis?\s+compras?)\b/i.test(mensajeLimpio) ||
        /\b(?:cancelar|cancela)\s+(?:pedido|orden)\s*#?\d+\b/i.test(mensajeLimpio) ||
        /\b(hola|buenas|buenos dias|buenas tardes|buenas noches|buen dia)\b/i.test(mensajeLimpio);

      if (esComando) {
        console.log('⚠️ Comando detectado en esperando_nombre — borrando sesión y rerutando');
        try {
          await this.helpers.httpRequest({
            method: 'DELETE',
            url: `http://host.docker.internal:3000/api/pedidos/sesion/${webhook.empresaId}/${webhook.numeroOrigen}`,
            json: true
          });
        } catch(e) {}
      } else {
        if (mensaje.trim().length < 3) {
          return {
            json: {
              ...config,
              numeroOrigen: webhook.numeroOrigen,
              empresaId: webhook.empresaId,
              nombreSesion,
              pushName: webhook.pushName,
              jidOriginal,
              numeroDescifrado,
              mensaje_usuario: mensajeLimpio,
              mensaje: "⚠️ *Nombre muy corto*\n\n📝 Por favor escribe tu nombre completo (mínimo 3 caracteres).\n\n❌ O escribe *cancelar* para anular.",
              tipo: 'respuesta_directa',
              abierto
            }
          };
        }

        const datosPedido = typeof sesionData.data.datos_pedido === 'string' 
          ? JSON.parse(sesionData.data.datos_pedido) 
          : sesionData.data.datos_pedido;

        return {
          json: {
            ...config,
            numeroOrigen: webhook.numeroOrigen,
            empresaId: webhook.empresaId,
            nombreSesion,
            pushName: webhook.pushName,
            jidOriginal,
            numeroDescifrado,
            nombreCliente: mensaje.trim(),
            items: datosPedido.items,
            total: datosPedido.total,
            tipo: 'crear_pedido',
            mensaje: '✅ *Confirmando tu pedido...*',
            mensaje_usuario: mensajeLimpio,
            abierto
          }
        };
      }
    }
  }
} catch (error) {
  console.log('ℹ️ No hay sesión activa o error:', error.message);
}

if (esCancelarGeneral) {
  return {
    json: {
      ...config,
      numeroOrigen: webhook.numeroOrigen,
      empresaId: webhook.empresaId,
      nombreSesion,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      mensaje_usuario: mensajeLimpio,
      mensaje: "ℹ️ *No tienes ningún pedido activo*\n\n📋 Escribe *productos* para ver nuestro catálogo\n🛒 O escribe tu pedido directamente\n\n💬 ¿En qué puedo ayudarte?",
      tipo: 'respuesta_directa',
      abierto
    }
  };
}

const patronPedido = /^\d+,\d+(;\d+,\d+)*$/;
if (patronPedido.test(mensajeLimpio)) {
  return {
    json: {
      ...config,
      numeroOrigen: webhook.numeroOrigen,
      empresaId: webhook.empresaId,
      nombreSesion,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      mensaje_usuario: mensajeLimpio,
      tipo: 'procesar_pedido',
      mensaje: '🛒 *Procesando tu pedido...*',
      abierto,
      hora_actual: hour,
      dia_actual: day
    }
  };
}

const mensajeLower = mensajeLimpio.toLowerCase();
let tipoMensaje = 'fallback';
let mensajeRespuesta = '';

const confirmacionesSimples = ['si', 'sí', 'ok', 'vale', 'okey', 'okay', 'de acuerdo', 'claro', 'bueno', 'listo', 'entendido', 'perfecto', 'dale', 'ya', 'bien'];
if (confirmacionesSimples.includes(mensajeLower)) {
  return {
    json: {
      ...config,
      mensaje_usuario: mensajeLimpio,
      numeroOrigen: webhook.numeroOrigen,
      pushName: webhook.pushName,
      jidOriginal,
      numeroDescifrado,
      empresaId: webhook.empresaId,
      nombreSesion,
      conectado: config.conectado,
      abierto,
      hora_actual: hour,
      dia_actual: day,
      tipo: 'fallback',
      mensaje: abierto ? config.mensaje_horario : config.mensaje_fuera_horario,
      mensaje_respuesta: abierto ? config.mensaje_horario : config.mensaje_fuera_horario
    }
  };
}

const saludos = ['hola', 'buenas', 'buenos dias', 'buenas tardes', 'buenas noches', 'buen dia', 'hey', 'ola', 'que tal', 'buenos días'];
if (saludos.some(s => mensajeLower.includes(s))) {
  tipoMensaje = 'saludo_inicial';
}
else if (mensajeLower.includes(config.trigger_horarios || 'horario') || 
         mensajeLower.includes('hora') || 
         mensajeLower.includes('cuando abren') || 
         mensajeLower.includes('cuando cierran') ||
         mensajeLower.includes('que hora') ||
         mensajeLower.includes('a que hora')) {
  tipoMensaje = 'mostrar_horario';
}
else if (mensajeLower.includes(config.trigger_productos || 'productos') || 
         mensajeLower.includes('catalogo') || 
         mensajeLower.includes('catálogo') || 
         mensajeLower.includes('que tienen') || 
         mensajeLower.includes('que venden') ||
         mensajeLower.includes('menu') ||
         mensajeLower.includes('menú') ||
         mensajeLower.includes('ver productos')) {
  tipoMensaje = 'productos';
}
else if (mensajeLower.includes('ayuda') || mensajeLower.includes('opciones')) {
  tipoMensaje = 'saludo_inicial';
}
else {
  tipoMensaje = 'fallback';
  mensajeRespuesta = abierto ? config.mensaje_horario : config.mensaje_fuera_horario;
}

console.log('📤 Tipo:', tipoMensaje);

return {
  json: {
    ...config,
    mensaje_usuario: mensajeLimpio,
    numeroOrigen: webhook.numeroOrigen,
    pushName: webhook.pushName,
    jidOriginal,
    numeroDescifrado,
    empresaId: webhook.empresaId,
    nombreSesion,
    conectado: config.conectado,
    abierto,
    hora_actual: hour,
    dia_actual: day,
    tipo: tipoMensaje,
    mensaje: mensajeRespuesta || (abierto ? config.mensaje_horario : config.mensaje_fuera_horario),
    mensaje_respuesta: abierto ? config.mensaje_horario : config.mensaje_fuera_horario
  }
};

const config = $('HTTP Request').first().json;
const switchData = $('Switch').first().json;

let nombreSesion = switchData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${switchData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${switchData.empresaId}_`.length);
}

let bdData = null;
try {
  bdData = $('Analizar Mensaje BD').first().json;
} catch (e) {}

let mensaje = '';

if (bdData && bdData.debe_responder === true && bdData.respuesta?.texto) {
  mensaje = bdData.respuesta.texto;
} else {
  const horaInicio = config.hora_inicio || 9;
  const horaFin = config.hora_fin || 18;
  const diasLaborales = config.dias_laborales || [1, 2, 3, 4, 5];
  const nombresDias = { 0: 'Domingo', 1: 'Lunes', 2: 'Martes', 3: 'Miércoles', 4: 'Jueves', 5: 'Viernes', 6: 'Sábado' };
  const diasTexto = diasLaborales.map(d => nombresDias[d]).join(', ');
  mensaje = `🕐 *Horario de Atención*\n\n📅 *Días laborales:*\n${diasTexto}\n\n⏰ *Horario:*\n${horaInicio}:00 hrs - ${horaFin}:00 hrs\n\n━━━━━━━━━━━━━━━━━━━━━\n\n💬 ¿En qué más puedo ayudarte?\n\n📋 Escribe *productos* para ver el catálogo\n🛒 O escribe tu pedido directamente`;
}

return {
  json: {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion: nombreSesion,
    mensaje: mensaje
  }
};

const httpData = $input.first().json;
const switchData = $('Switch').first().json;

const productos = (httpData.data || []).filter(p => {
  if (p.stock === null || p.stock === undefined) return true;
  return p.stock > 0;
});

let nombreSesion = switchData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${switchData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${switchData.empresaId}_`.length);
}

if (!productos || productos.length === 0) {
  return {
    json: {
      numeroOrigen: switchData.numeroOrigen,
      empresaId: switchData.empresaId,
      nombreSesion,
      mensaje: "📦 No hay productos disponibles actualmente.",
      productosConImagen: []
    }
  };
}

// Extraer categorías únicas
const categoriasMap = {};
productos.forEach(p => {
  if (p.categoria && p.categoria.id) {
    categoriasMap[p.categoria.id] = p.categoria.nombre;
  }
});
const categorias = Object.entries(categoriasMap)
  .map(([id, nombre]) => ({ id: parseInt(id), nombre }))
  .sort((a, b) => a.nombre.localeCompare(b.nombre));

// Sin categorías → mostrar todos directo
if (categorias.length === 0) {
  let mensajeCompleto = '📦 *Catálogo de Productos*\n\n';
  const productosConImagen = [];
  let contador = 1;
  productos.forEach(p => {
    const numero = contador++;
    mensajeCompleto += `*${numero}.* ${p.nombre_item}\n`;
    if (p.precio) mensajeCompleto += `💰 $${parseFloat(p.precio).toFixed(2)}\n`;
    if (p.descripcion) mensajeCompleto += `📝 ${p.descripcion}\n`;
    mensajeCompleto += '\n';
    if (p.imagen_url && p.imagen_url.trim() !== '' && p.imagen_url !== 'null' && p.imagen_url !== 'undefined') {
      productosConImagen.push({
        numero, nombre: p.nombre_item,
        precio: p.precio ? `${parseFloat(p.precio).toFixed(2)}` : '',
        descripcion: p.descripcion || '',
        imagen_url: p.imagen_url
      });
    }
  });
  mensajeCompleto += `━━━━━━━━━━━━━━━━━━━━━\n\n🛒 *¿Cómo hacer tu pedido?*\n\n📋 Escribe: *número,cantidad*\n\n✏️ Escribe tu pedido ahora o *cancelar* para salir.`;
  return {
    json: {
      numeroOrigen: switchData.numeroOrigen,
      empresaId: switchData.empresaId,
      nombreSesion,
      pushName: switchData.pushName,
      mensaje: mensajeCompleto,
      productosConImagen
    }
  };
}

// HAY CATEGORÍAS → borrar sesión vieja y guardar nueva
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: `http://host.docker.internal:3000/api/pedidos/sesion/${switchData.empresaId}/${switchData.numeroOrigen}`,
    json: true
  });
  console.log('🗑️ Sesión anterior borrada');
} catch(e) {
  console.log('ℹ️ No había sesión previa:', e.message);
}

try {
  const postResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:3000/api/pedidos/sesion',
    body: {
      empresaId: switchData.empresaId,
      numeroOrigen: switchData.numeroOrigen,
      nombreSesion: nombreSesion,
      pushName: switchData.pushName,
      jidOriginal: switchData.jidOriginal || '',
      numeroDescifrado: switchData.numeroDescifrado || false,
      estado: 'seleccionando_categoria',
      datosPedido: { categorias }
    },
    json: true
  });
  console.log('✅ Sesión guardada:', JSON.stringify(postResult));
} catch(e) {
  console.log('❌ Error guardando sesión:', e.message);
}

let mensaje = '📦 *Catálogo de Productos*\n\n¿Qué categoría te interesa?\n\n';
categorias.forEach((cat, i) => {
  mensaje += `*${i + 1}.* ${cat.nombre}\n`;
});
mensaje += `*0.* Ver todos los productos\n\n✏️ Escribe el *número* de la categoría o *cancelar* para salir.`;

return {
  json: {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion,
    pushName: switchData.pushName,
    mensaje,
    productosConImagen: []
  }
};

const httpData = $input.first().json;
const switchData = $('Switch').first().json;

const todosLosProductos = (httpData.data || []).filter(p => {
  if (p.stock === null || p.stock === undefined) return true;
  return p.stock > 0;
});

let nombreSesion = switchData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${switchData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${switchData.empresaId}_`.length);
}

const categoriaOpcion = switchData.categoriaOpcion;
const categorias = switchData.categorias || [];

// ✅ FIXED: usar this.helpers.httpRequest en lugar de fetch
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: `http://host.docker.internal:3000/api/pedidos/sesion/${switchData.empresaId}/${switchData.numeroOrigen}`,
    json: true
  });
  console.log('🗑️ Sesión de categoría borrada');
} catch(e) {
  console.log('ℹ️ No había sesión que borrar:', e.message);
}

let productosFiltrados;
let tituloCatalogo;

if (categoriaOpcion === 0) {
  productosFiltrados = todosLosProductos;
  tituloCatalogo = '📦 *Catálogo Completo*';
} else {
  const categoriaElegida = categorias[categoriaOpcion - 1];
  if (!categoriaElegida) {
    return {
      json: {
        numeroOrigen: switchData.numeroOrigen,
        empresaId: switchData.empresaId,
        nombreSesion,
        pushName: switchData.pushName,
        mensaje: `❌ Opción no válida. Escribe *productos* para ver el catálogo.`,
        productosConImagen: []
      }
    };
  }
  productosFiltrados = todosLosProductos.filter(p =>
    p.categoria && p.categoria.id === categoriaElegida.id
  );
  tituloCatalogo = `📦 *${categoriaElegida.nombre}*`;
}

if (!productosFiltrados || productosFiltrados.length === 0) {
  return {
    json: {
      numeroOrigen: switchData.numeroOrigen,
      empresaId: switchData.empresaId,
      nombreSesion,
      pushName: switchData.pushName,
      mensaje: `${tituloCatalogo}\n\n⚠️ No hay productos disponibles en esta categoría.\n\nEscribe *productos* para ver otras categorías.`,
      productosConImagen: []
    }
  };
}

let mensajeCompleto = `${tituloCatalogo}\n\n`;
const productosConImagen = [];
let contador = 1;

productosFiltrados.forEach(p => {
  const numero = contador++;
  mensajeCompleto += `*${numero}.* ${p.nombre_item}\n`;
  if (p.precio) mensajeCompleto += `💰 $${parseFloat(p.precio).toFixed(2)}\n`;
  if (p.descripcion) mensajeCompleto += `📝 ${p.descripcion}\n`;
  mensajeCompleto += '\n';
  if (p.imagen_url && p.imagen_url.trim() !== '' && p.imagen_url !== 'null' && p.imagen_url !== 'undefined') {
    productosConImagen.push({
      numero,
      nombre: p.nombre_item,
      precio: p.precio ? `${parseFloat(p.precio).toFixed(2)}` : '',
      descripcion: p.descripcion || '',
      imagen_url: p.imagen_url
    });
  }
});

mensajeCompleto += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
mensajeCompleto += `🛒 *¿Cómo hacer tu pedido?*\n\n`;
mensajeCompleto += `📋 Escribe: *número,cantidad*\n`;
mensajeCompleto += `Ejemplo: *1,2* (producto 1, cantidad 2)\n\n`;
mensajeCompleto += `🏷️ Escribe *productos* para ver otras categorías o *cancelar* para salir.`;

return {
  json: {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion,
    pushName: switchData.pushName,
    mensaje: mensajeCompleto,
    productosConImagen
  }
};

const switchData = $('Switch').first().json;
const productosResponse = $input.first().json;
const productos = productosResponse.data;

let nombreSesion = switchData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${switchData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${switchData.empresaId}_`.length);
}

const pedidoStr = switchData.mensaje_usuario;

if (!pedidoStr || pedidoStr.trim() === '') {
  return {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion: nombreSesion,
    pushName: switchData.pushName,
    mensaje: "⚠️ *Formato incorrecto*\n\nEscribe el número del producto y la cantidad.\n\n📌 Ejemplo: *1,2* (producto 1, cantidad 2)",
    tipo: 'error_formato',
    pedido_temporal: null
  };
}

const pares = pedidoStr.split(';').map(p => p.trim()).filter(p => p);
const items = [];
let total = 0;
let errorMsg = '';

for (const par of pares) {
  const partes = par.split(',').map(p => p.trim());
  if (partes.length !== 2) {
    errorMsg = `⚠️ *Formato incorrecto*\n\nUsa: *número,cantidad*\n\n✅ Ejemplo: *1,2* (2 unidades del producto #1)\n\n📋 Escribe *productos* para ver el catálogo`;
    break;
  }
  const [numeroStr, cantStr] = partes;
  const numeroCatalogo = parseInt(numeroStr);
  const cantidad = parseInt(cantStr);
  if (isNaN(numeroCatalogo) || isNaN(cantidad) || cantidad <= 0 || numeroCatalogo <= 0) {
    errorMsg = `⚠️ *Formato incorrecto*\n\nUsa: *número,cantidad*\n\n✅ Ejemplo: *1,2* (2 unidades del producto #1)\n\n📋 Escribe *productos* para ver el catálogo`;
    break;
  }
  const indiceProducto = numeroCatalogo - 1;
  if (indiceProducto < 0 || indiceProducto >= productos.length) {
    errorMsg = `⚠️ *Producto #${numeroCatalogo} no existe*\n\n📦 Tenemos ${productos.length} productos disponibles\n\n📋 Escribe *productos* para ver el catálogo completo`;
    break;
  }
  const producto = productos[indiceProducto];
  if (!producto.precio || isNaN(parseFloat(producto.precio))) {
    errorMsg = `⚠️ *Error en producto #${numeroCatalogo}*\n\nEl producto no tiene precio válido.\n\n📋 Escribe *productos* para ver el catálogo`;
    break;
  }
  const subtotal = parseFloat(producto.precio) * cantidad;
  total += subtotal;
  items.push({
    producto_id: producto.id,
    nombre: producto.nombre_item,
    cantidad: cantidad,
    precio_unitario: parseFloat(producto.precio),
    subtotal: subtotal
  });
}

if (errorMsg) {
  return {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion: nombreSesion,
    pushName: switchData.pushName,
    mensaje: errorMsg,
    tipo: 'error_pedido',
    pedido_temporal: null
  };
}

let resumen = '🛒 *Resumen de tu pedido:*\n\n';
items.forEach((item, i) => {
  resumen += `${i + 1}. ${item.nombre}\n`;
  resumen += `   💰 $${item.precio_unitario.toFixed(2)} × ${item.cantidad} = $${item.subtotal.toFixed(2)}\n\n`;
});
resumen += `━━━━━━━━━━━━━━━━━━━━━\n`;
resumen += `💵 *Total: $${total.toFixed(2)}*\n\n`;
resumen += `✅ *Confirmando tu pedido...*`;

return {
  numeroOrigen: switchData.numeroOrigen,
  empresaId: switchData.empresaId,
  nombreSesion: nombreSesion,
  pushName: switchData.pushName,
  mensaje: resumen,
  tipo: 'pedir_nombre',
  pedido_temporal: {
    items: items,
    total: total,
    estado: 'esperando_nombre',
    fecha_creacion: new Date().toISOString()
  }
};

const procesarData = $input.first().json;
const switchData = $('Switch').first().json;
let nombreSesion = switchData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${switchData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${switchData.empresaId}_`.length);
}
return {
  json: {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion: nombreSesion,
    pushName: switchData.pushName,
    mensaje: procesarData.mensaje,
    pedido_temporal: procesarData.pedido_temporal,
    tipo: procesarData.tipo,
    abierto: !!switchData.abierto
  }
};

