const codeData = $('Validar y Clasificar').first().json;
const webhookData = $('Recibir Mensaje').first().json.body;
const config = $('HTTP Request').first().json;
const nombreUsuario = webhookData.pushName || 'amigo';

let nombreSesion = codeData.nombreSesion;
if (nombreSesion && nombreSesion.startsWith(`${codeData.empresaId}_`)) {
  nombreSesion = nombreSesion.substring(`${codeData.empresaId}_`.length);
}

const mensajeBienvenida = config.mensaje_horario;
let mensaje = '';

if (mensajeBienvenida && mensajeBienvenida.trim() !== '') {
  mensaje = mensajeBienvenida.replace('{nombre}', nombreUsuario);
} else {
  mensaje = `👋 ¡Hola ${nombreUsuario}! Bienvenido(a)\n\n¿En qué puedo ayudarte hoy?\n\n📋 Escribe *productos* para ver el catálogo\n🕐 Escribe *horarios* para ver horarios\n📦 Escribe *mis pedidos* para ver tus pedidos\n\n💡 *Tip:* Cuando veas el catálogo, pide así:\n*número,cantidad* (ejemplo: *1,2* para 2 del producto #1)\n\n💬 ¿Qué necesitas?`;
}

return {
  json: {
    numeroOrigen: codeData.numeroOrigen,
    empresaId: codeData.empresaId,
    nombreSesion: nombreSesion,
    mensaje: mensaje
  }
};

const pedidosResponse = $input.first().json;
const switchData = $('Switch').first().json;

console.log('📋 Respuesta de pedidos:', JSON.stringify(pedidosResponse, null, 2));

if (!pedidosResponse.success || !pedidosResponse.data || pedidosResponse.data.length === 0) {
  return {
    json: {
      numeroOrigen: switchData.numeroOrigen,
      empresaId: switchData.empresaId,
      nombreSesion: switchData.nombreSesion,
      pushName: switchData.pushName,
      mensaje: "📦 *No tienes pedidos registrados*\n\n✅ Escribe *productos* para ver el catálogo y hacer tu primer pedido."
    }
  };
}

const pedidos = pedidosResponse.data;

function formatearFecha(fechaISO) {
  const fecha = new Date(fechaISO);
  return fecha.toLocaleDateString('es-MX', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit', hour12: true });
}

function formatearEstado(estado) {
  const estados = { 'pendiente': '⏳ Pendiente', 'confirmado': '✅ Confirmado', 'en_proceso': '🔄 En Proceso', 'entregado': '📦 Entregado', 'cancelado': '❌ Cancelado' };
  return estados[estado] || estado;
}

let mensaje = `📋 *Tus Pedidos (${pedidos.length})*\n\n`;

pedidos.forEach((pedido, index) => {
  const fecha = formatearFecha(pedido.fecha_pedido);
  const estado = formatearEstado(pedido.estado);
  const total = parseFloat(pedido.total).toFixed(2);
  let emoji = '⏳';
  if (pedido.estado === 'confirmado') emoji = '✅';
  if (pedido.estado === 'en_proceso') emoji = '🔄';
  if (pedido.estado === 'entregado') emoji = '📦';
  if (pedido.estado === 'cancelado') emoji = '❌';
  mensaje += `${emoji} *Pedido #${pedido.id}*\n`;
  mensaje += `📅 ${fecha}\n`;
  mensaje += `💵 Total: $${total}\n`;
  mensaje += `📊 Estado: ${estado}\n`;
  if (pedido.items && pedido.items.length > 0) {
    mensaje += `📦 Productos:\n`;
    pedido.items.forEach(item => {
      const precio = item.precio_unitario || item.precio || 0;
      mensaje += `   • ${item.cantidad}x ${item.nombre} - $${parseFloat(precio).toFixed(2)}\n`;
    });
  }
  if (pedido.estado === 'pendiente' || pedido.estado === 'confirmado') {
    mensaje += `\n❌ Para cancelar: *cancelar pedido ${pedido.id}*\n`;
  }
  mensaje += `\n━━━━━━━━━━━━━━━━━━━━━\n`;
  if (index < pedidos.length - 1) mensaje += `\n`;
});

mensaje += `\n💬 *¿Necesitas algo más?*\n`;
mensaje += `📋 Escribe *productos* para ver el catálogo\n`;
mensaje += `📞 Escribe *horarios* para ver nuestro horario`;

return {
  json: {
    numeroOrigen: switchData.numeroOrigen,
    empresaId: switchData.empresaId,
    nombreSesion: switchData.nombreSesion,
    pushName: switchData.pushName,
    mensaje: mensaje
  }
};

const data = $input.first().json;
const productosConImagen = data.productosConImagen || [];
if (productosConImagen.length === 0) return [];
return productosConImagen.map((p, i) => ({
  json: {
    numeroOrigen: data.numeroOrigen,
    empresaId: data.empresaId,
    nombreSesion: data.nombreSesion,
    imagenUrl: p.imagen_url,
    caption: `*${p.numero}.* ${p.nombre}\n${p.precio ? `💰 Precio: $${p.precio}\n` : ''}${p.descripcion ? `📝 ${p.descripcion}` : ''}`,
    orden: i
  }
}));

const switchData = $('Switch').first().json;
const detalleResponse = $input.first().json;

if (!detalleResponse.success || !detalleResponse.data) {
  return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, mensaje: `❌ *Pedido #${switchData.pedidoId} no encontrado*\n\n📋 Escribe *mis pedidos* para ver tus pedidos activos.`, esError: true } };
}

const pedido = detalleResponse.data;

if (pedido.telefono_cliente !== switchData.numeroOrigen) {
  return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, mensaje: `❌ *No tienes permiso para cancelar este pedido*\n\n📋 Escribe *mis pedidos* para ver tus pedidos.`, esError: true } };
}

if (pedido.estado === 'cancelado') {
  return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, mensaje: `ℹ️ *El pedido #${switchData.pedidoId} ya está cancelado*\n\n📋 Escribe *mis pedidos* para ver tus otros pedidos.`, esError: true } };
}

if (pedido.estado === 'entregado') {
  return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, mensaje: `❌ *No puedes cancelar el pedido #${switchData.pedidoId}*\n\nEl pedido ya fue entregado.\n\n📞 Contacta con soporte si necesitas ayuda.`, esError: true } };
}

if (pedido.estado === 'enviado' || pedido.estado === 'en_proceso') {
  return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, mensaje: `⚠️ *El pedido #${switchData.pedidoId} ya está en camino*\n\nNo puede ser cancelado automáticamente.\n\n📞 Contacta con soporte para cancelarlo.`, esError: true } };
}

return { json: { numeroOrigen: switchData.numeroOrigen, empresaId: switchData.empresaId, nombreSesion: switchData.nombreSesion, pushName: switchData.pushName, pedidoId: switchData.pedidoId, pedidoData: pedido, esError: false } };

const cancelResponse = $input.first().json;
const validarData = $('Validar Pedido').first().json;
if (cancelResponse.success) {
  const total = validarData.pedidoData.total || 0;
  return { json: { numeroOrigen: validarData.numeroOrigen, empresaId: validarData.empresaId, nombreSesion: validarData.nombreSesion, pushName: validarData.pushName, mensaje: `✅ *Pedido #${validarData.pedidoId} cancelado exitosamente*

💵 Total cancelado: $${parseFloat(total).toFixed(2)}

━━━━━━━━━━━━━━━━━━━━━

📋 Escribe *pedidos* para ver tu historial
🛒 Escribe *productos* para hacer un nuevo pedido` } };
} else {
  return { json: { numeroOrigen: validarData.numeroOrigen, empresaId: validarData.empresaId, nombreSesion: validarData.nombreSesion, pushName: validarData.pushName, mensaje: `❌ *Error al cancelar el pedido #${validarData.pedidoId}*

${cancelResponse.mensaje || 'Por favor intenta de nuevo'}` } };
}

const empresa = $input.first().json;
const filasProductos = empresa.productos.map(p => {
  let colorStock, labelStock;
  if (p.stock === 0) { colorStock = '#dc3545'; labelStock = 'AGOTADO'; }
  else if (p.stock <= 2) { colorStock = '#fd7e14'; labelStock = `${p.stock} uds - CRÍTICO`; }
  else { colorStock = '#ffc107'; labelStock = `${p.stock} uds - BAJO`; }
  const precio = p.precio ? `$${parseFloat(p.precio).toFixed(2)}` : '—';
  return `<tr><td style="padding:10px;border-bottom:1px solid #eee">${p.nombre}</td><td style="padding:10px;border-bottom:1px solid #eee;text-align:center"><span style="background:${colorStock};color:#fff;padding:3px 10px;border-radius:12px;font-size:12px">${labelStock}</span></td><td style="padding:10px;border-bottom:1px solid #eee;text-align:center">${precio}</td></tr>`;
}).join('');
const fecha = new Date().toLocaleDateString('es-MX', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const htmlEmail = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto"><div style="background:#FF6B35;padding:25px;border-radius:8px 8px 0 0"><h2 style="color:#fff;margin:0">📦 Alerta de Stock Bajo</h2><p style="color:rgba(255,255,255,0.85);margin:5px 0 0">${empresa.nombreEmpresa}</p></div><div style="padding:25px;border:1px solid #eee"><p>Hola <strong>${empresa.nombreContacto}</strong>,</p><p>Reporte del <strong>${fecha}</strong>. Los siguientes productos necesitan reabastecimiento:</p><table style="width:100%;border-collapse:collapse"><thead><tr style="background:#f8f9fa"><th style="padding:10px;text-align:left;border-bottom:2px solid #eee">Producto</th><th style="padding:10px;text-align:center;border-bottom:2px solid #eee">Stock</th><th style="padding:10px;text-align:center;border-bottom:2px solid #eee">Precio</th></tr></thead><tbody>${filasProductos}</tbody></table><p style="margin-top:20px;font-size:13px;color:#888">Umbral configurado: ≤ ${empresa.umbralUsado} unidades</p></div><div style="background:#f8f9fa;padding:15px;text-align:center;font-size:12px;color:#aaa">Notificación automática · ${empresa.nombreEmpresa}</div></div>`;
return { json: { emailDestino: empresa.emailDestino, nombreEmpresa: empresa.nombreEmpresa, asunto: `⚠️ ${empresa.totalProductosBajos} producto(s) con stock bajo — ${empresa.nombreEmpresa}`, htmlEmail } };
